cfm.maintenance-group:
      ${maintenance\-group\-id}
      ${md\-id}
      ${ma\-id}
      <#if mep\-id?has_content>

        ${mep\-id}
        ${direction}
	<#if ccm\-ltm\-priority?has_content>
        ${ccm\-ltm\-priority}
        </#if>
	<#if inactive\-remote\-mep?has_content>

          ${inactive\-remote\-mep}

        </#if>
	<#if ccm\-enabled?has_content || fault\-alarm\-transmission?has_content || lowest\-priority\-defect?has_content || fng\-alarm\-time?has_content || fng\-reset\-time?has_content>

	  <#if ccm\-enabled?has_content>
            ${ccm\-enabled}
          </#if>
	  <#if fault\-alarm\-transmission?has_content>
            ${fault\-alarm\-transmission}
          </#if>
	  <#if lowest\-priority\-defect?has_content>
            ${lowest\-priority\-defect}
          </#if>
	    <#if fng\-alarm\-time?has_content>
          ${fng\-alarm\-time}
          </#if>
	  <#if fng\-reset\-time?has_content>
            ${fng\-reset\-time}
          </#if>

        </#if>
	<#if ccm\-ltm\-inner\-tag\-priority?has_content>
        ${ccm\-ltm\-inner\-tag\-priority}
        </#if>
        <#if mep\-state?has_content>
        ${mep\-state}
        </#if>
        ${interface}

      </#if>
      <#if forwarder?has_content>
      ${forwarder}
      </#if>
